        public static MappedDomain Map(this Domains domain)
        {
            return new MappedDomain(
                domain.DomainName, 
                domain.DomainAliases.Map(),
                domain.ETag,
                domain.Kind,
                domain.IsPrimary,
                new DateTime(domain.CreationTime ?? 0),
                domain.Verified);
        }

        private static IEnumerable<MappedDomainAlias> Map(this IList<DomainAlias>? domainAliases)
        {
            if (domainAliases == null)
            {
                return new List<MappedDomainAlias>();
            }

            return domainAliases.Select(x => new MappedDomainAlias(
                x.DomainAliasName,
                x.ETag,
                x.Kind,
                x.ParentDomainName,
                new DateTime(x.CreationTime ?? 0),
                x.Verified));
        }
    }
