namespace Ao.Wrappers.Google.Repositories;

public class ClientSettingsRepository : IClientSettingsRepository
{
    private readonly IConfiguration _configuration;

    public ClientSettingsRepository(IConfiguration? configuration = null)
    {
        _configuration = configuration ?? new ConfigurationBuilder()
            .AddJsonFile("appsettings.json", optional: true, reloadOnChange: false)
            .AddJsonFile("secrets.json", optional: true, reloadOnChange: false)
            .AddUserSecrets<ClientSettingsRepository>(optional: true)
            .Build();
    }

    public ClientSettings Retrieve()
    {
        var settings = _configuration.GetSection("Google").Get<ClientSettings>();

        Throw<InvalidOperationException>(settings is not null, "Google settings are missing from configuration or user secrets.");
        Throw<InvalidOperationException>(!string.IsNullOrWhiteSpace(settings!.Customer), "Google:Customer is required.");
        Throw<InvalidOperationException>(!string.IsNullOrWhiteSpace(settings.User), "Google:User is required.");
        Throw<InvalidOperationException>(!string.IsNullOrWhiteSpace(settings.Application), "Google:Application is required.");
        Throw<InvalidOperationException>(settings.Scopes is not null && settings.Scopes.Length > 0, "Google:Scopes is required.");
        Throw<InvalidOperationException>(!string.IsNullOrWhiteSpace(settings.ClientId), "Google:ClientId is required.");
        Throw<InvalidOperationException>(!string.IsNullOrWhiteSpace(settings.ClientSecret), "Google:ClientSecret is required.");

        return settings;
    }
}

